handlerCreate.perform:
if (object.id !== 'item:bubble-solution-vial') return { output: `You can't put ${lib.ref(object)} into the thrower.`, events: [] };
if (indirect.id !== 'item:gurgling-bubble-thrower') return { output: `You can only pour the concentrate into the bubble-thrower.`, events: [] };
if (indirect.properties.switchedOn) return { output: 'The thrower is already primed and gurgling.', events: [] };

indirect.properties.switchedOn = true;
return {
  output: `You carefully pour the Joy Concentrate into the reservoir of the bubble-thrower. The device let out a happy gurgle, and a soft blue glow begins to emanate from the nozzle.`,
  events: [
    { type: 'set-property', entityId: indirect.id, property: 'switchedOn', value: true, description: 'Primed the bubble thrower.' },
    { type: 'delete-entity', entityId: object.id, description: 'Empty vial discarded.' }
  ]
};

if (object.id !== 'item:gurgling-bubble-thrower') return { output: `You can't shoot with ${lib.ref(object)}.`, events: [] };
if (indirect.id !== 'item:ornery-service-bot') return { output: 'The bubble-thrower is meant for spreading joy, not random target practice.', events: [] };
if (!object.properties.switchedOn) return { output: 'The bubble-thrower just makes a sad, dry clicking sound. It needs fluid.', events: [] };

const room = store.get('room:the-commons-west');
const exit = store.get('exit:the-commons-west:northwest');

return {
  output: `You crank the handle of the bubble-thrower and aim the trumpet-nozzle at the service-bot. A massive, shimmering blue bubble wobbles out and slowly drifts toward the droid. It lands squarely on the bot's sensor-eye with a wet 'POP!'\n\nThe bot stops humming. It lets out a long, digital sigh that sounds suspiciously like 'Finally...' and begins to perform a slow, rhythmic dance, completely forgetting its duty to block the path. The way to the Weaving District is now clear.`,
  events: [
    { type: 'set-property', entityId: indirect.id, property: 'description', value: 'The service-bot is spinning in happy circles, covered in shimmering soap residue.', description: 'The bot is distracted.' },
    { type: 'set-property', entityId: indirect.id, property: 'name', value: 'Happy Service-Bot', description: 'Renamed the bot.' },
    { type: 'set-property', entityId: 'exit:the-commons-west:northwest', property: 'accessLevel', value: 0, description: 'Path cleared.' }
  ]
};

